@error_handler
def dynamic_query():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    table_name = data.get('table')
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    order_by = data.get('order_by')
    order_direction = data.get('order_direction', 'ASC')
    limit = data.get('limit', 100)
    offset = data.get('offset', 0)
    
    if not table_name:
        return jsonify({'error': 'Table name is required'}), 400
    
    validate_table_name(table_name)
    
    if limit > MAX_LIMIT:
        limit = MAX_LIMIT
    
    query_parts = []
    query_params = []
    
    if columns == ['*']:
        select_clause = sql.SQL("SELECT * FROM {}").format(sql.Identifier(table_name))
    else:
        validated_columns = [validate_identifier(col) for col in columns]
        select_clause = sql.SQL("SELECT {} FROM {}").format(
            sql.SQL(', ').join(map(sql.Identifier, validated_columns)),
            sql.Identifier(table_name)
        )
    
    query_parts.append(select_clause)
    
    if filters:
        where_conditions = []
        for filter_item in filters:
            column = filter_item.get('column')
            operator = filter_item.get('operator')
            value = filter_item.get('value')
            
            if not column or not operator:
                raise ValueError('Filter must contain column and operator')
            
            validate_identifier(column)
            validated_operator = validate_operator(operator)
            
            if validated_operator in ['IS NULL', 'IS NOT NULL']:
                where_conditions.append(
                    sql.SQL("{} {}").format(
                        sql.Identifier(column),
                        sql.SQL(validated_operator)
                    )
                )
            elif validated_operator in ['IN', 'NOT IN']:
                if not isinstance(value, list):
                    raise ValueError(f'{validated_operator} operator requires a list value')
                placeholders = sql.SQL(', ').join(sql.Placeholder() * len(value))
                where_conditions.append(
                    sql.SQL("{} {} ({})").format(
                        sql.Identifier(column),
                        sql.SQL(validated_operator),
                        placeholders
                    )
                )
                query_params.extend(value)
            else:
                where_conditions.append(
                    sql.SQL("{} {} {}").format(
                        sql.Identifier(column),
                        sql.SQL(validated_operator),
                        sql.Placeholder()
                    )
                )
                query_params.append(value)
        
        if where_conditions:
            where_clause = sql.SQL(" WHERE {}").format(
                sql.SQL(' AND ').join(where_conditions)
            )
            query_parts.append(where_clause)
    
    if order_by:
        validate_identifier(order_by)
        if order_direction.upper() not in ['ASC', 'DESC']:
            order_direction = 'ASC'
        order_clause = sql.SQL(" ORDER BY {} {}").format(
            sql.Identifier(order_by),
            sql.SQL(order_direction.upper())
        )
        query_parts.append(order_clause)
    
    limit_clause = sql.SQL(" LIMIT {} OFFSET {}").format(
        sql.Literal(limit),
        sql.Literal(offset)
    )
    query_parts.append(limit_clause)
    
    final_query = sql.SQL('').join(query_parts)
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=RealDictCursor) as cursor:
            cursor.execute(final_query, query_params)
            results = cursor.fetchall()
            
            return jsonify({
                'success': True,
                'data': results,
                'count': len(results),
                'limit': limit,
                'offset': offset
            }), 200
    finally:
        conn.close()

